/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, InventDim))
    {
        _dataSourceCtx.setDatabaseOperation(DataEntityDatabaseOperation::None);
    }

    ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage))
    {
        this.insertUpdateTextBlockSetupParm(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean updateEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, InventDim))
    {
        _dataSourceCtx.setDatabaseOperation(DataEntityDatabaseOperation::None);
    }

    ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage))
    {
        this.insertUpdateTextBlockSetupParm(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

/// <summary>
///
/// </summary>
public void postLoad()
{
    FWFTextBlockSetupParm		setupParm;

    super();

    setupParm = FWFTextBlockSetupParm::find(this.SetupRefRefId);
    this.TextBlockParm_ICCopy                      = setupParm.ICCopy;
    this.TextBlockParm_DirectDeliveryCopy		   = setupParm.DirectDeliveryCopy;
    this.TextBlockParm_RelatedPOCopy			   = setupParm.RelatedPOCopy;
    this.TextBlockParm_InstanceRelationType        = setupParm.InstanceRelationType;
    this.TextBlockParm_Position                    = setupParm.Position;
    this.TextBlockParm_PrintOnPurchConfirmation    = setupParm.PrintOnPurchConfirmation;
    this.TextBlockParm_PrintOnPurchInvoice         = setupParm.PrintOnPurchInvoice;
    this.TextBlockParm_PrintOnPurchPackingSlip     = setupParm.PrintOnPurchPackingSlip;
    this.TextBlockParm_PrintOnPurchReceiptsList    = setupParm.PrintOnPurchReceiptsList;
    this.TextBlockParm_PrintOnSalesConfirmation    = setupParm.PrintOnSalesConfirmation;
    this.TextBlockParm_PrintOnSalesInvoice         = setupParm.PrintOnSalesInvoice;
    this.TextBlockParm_PrintOnSalesPackingSlip     = setupParm.PrintOnSalesPackingSlip;
    this.TextBlockParm_PrintOnSalesPickingList     = setupParm.PrintOnSalesPickingList;
    this.TextBlockParm_PrintOnSalesQuotation       = setupParm.PrintOnSalesQuotation;
    this.TextBlockParm_ShowWarning                 = setupParm.ShowWarning;
    this.TextBlockParm_SortOrder                   = setupParm.SortOrder;
    this.TextBlockParm_PrintOnCustFreeInvoice      = setupParm.PrintOnCustFreeInvoice;
    this.TextBlockParm_PrintOnPurchAgreement       = setupParm.PrintOnPurchAgreement;
    this.TextBlockParm_PrintOnSalesAgreement       = setupParm.PrintOnSalesAgreement;
    this.TextBlockParm_PrintOnProdJobCard		   = setupParm.PrintOnProdJobCard;
    this.TextBlockParm_PrintOnProdRouteCard		   = setupParm.PrintOnProdRouteCard;
    this.TextBlockParm_PrintOnProdPickList         = setupParm.PrintOnProdPickList;
    this.TextBlockParm_PrintOnProjQuotation		   = setupParm.PrintOnProjQuotation;
    this.TextBlockParm_PrintOnProjQuotationConfirm = setupParm.PrintOnProjQuotationConfirm;
    this.TextBlockParm_PrintOnProjInvoice          = setupParm.PrintOnProjInvoice;
    this.TextBlockParm_PrintOnPurchReq             = setupParm.PrintOnPurchReq;
    this.TextBlockParm_PrintOnPurchRFQCase         = setupParm.PrintOnPurchRFQCase;
}

    private void insertUpdateTextBlockSetupParm(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
    {
        FWFTextBlockUsage			textBlockUsage;
        FWFTextBlockTable			textBlockTable;
        FWFTextBlockSetupParm		textBlockSetupParm;
        FWFTextBlockSetupGroup		textBlockSetupGroup;
        FWFTextBlockSetupGroupParm	textBlockSetupGroupParm;
        FWFTextBlockUsageEntity		textBlockUsageEntity;

        textBlockUsage       = _dataSourceCtx.getBuffer();
        textBlockUsageEntity = _entityCtx.getEntityRecord();

        textBlockSetupGroup = FWFTextBlockSetupGroup::findGroupModule(textBlockUsage.SetupGroupId, textBlockUsage.module());
        if (textBlockSetupGroup)
        {
            textBlockSetupGroupParm = FWFTextBlockSetupGroupParm::find(textBlockSetupGroup.SetupRecId);
        }

		textBlockSetupParm = FWFTextBlockSetupParm::find(textBlockUsage.SetupRefRefId, true);
        if (! textBlockSetupGroupParm)
        {
            textBlockSetupParm.ICCopy                      = textBlockUsageEntity.TextBlockParm_ICCopy;
            textBlockSetupParm.DirectDeliveryCopy		   = textBlockUsageEntity.TextBlockParm_DirectDeliveryCopy;
            textBlockSetupParm.RelatedPOCopy			   = textBlockUsageEntity.TextBlockParm_RelatedPOCopy;
            textBlockSetupParm.InstanceRelationType        = textBlockUsageEntity.TextBlockParm_InstanceRelationType;
            textBlockSetupParm.Position                    = textBlockUsageEntity.TextBlockParm_Position;
            textBlockSetupParm.PrintOnPurchConfirmation    = textBlockUsageEntity.TextBlockParm_PrintOnPurchConfirmation;
            textBlockSetupParm.PrintOnPurchInvoice         = textBlockUsageEntity.TextBlockParm_PrintOnPurchInvoice;
            textBlockSetupParm.PrintOnPurchPackingSlip     = textBlockUsageEntity.TextBlockParm_PrintOnPurchPackingSlip;
            textBlockSetupParm.PrintOnPurchReceiptsList    = textBlockUsageEntity.TextBlockParm_PrintOnPurchReceiptsList;
            textBlockSetupParm.PrintOnSalesConfirmation    = textBlockUsageEntity.TextBlockParm_PrintOnSalesConfirmation;
            textBlockSetupParm.PrintOnSalesInvoice         = textBlockUsageEntity.TextBlockParm_PrintOnSalesInvoice;
            textBlockSetupParm.PrintOnSalesPackingSlip     = textBlockUsageEntity.TextBlockParm_PrintOnSalesPackingSlip;
            textBlockSetupParm.PrintOnSalesPickingList     = textBlockUsageEntity.TextBlockParm_PrintOnSalesPickingList;
            textBlockSetupParm.PrintOnSalesQuotation       = textBlockUsageEntity.TextBlockParm_PrintOnSalesQuotation;
            textBlockSetupParm.ShowWarning                 = textBlockUsageEntity.TextBlockParm_ShowWarning;
            textBlockSetupParm.SortOrder                   = textBlockUsageEntity.TextBlockParm_SortOrder;
            textBlockSetupParm.PrintOnCustFreeInvoice      = textBlockUsageEntity.TextBlockParm_PrintOnCustFreeInvoice;
            textBlockSetupParm.PrintOnPurchAgreement       = textBlockUsageEntity.TextBlockParm_PrintOnPurchAgreement;
            textBlockSetupParm.PrintOnSalesAgreement       = textBlockUsageEntity.TextBlockParm_PrintOnSalesAgreement;
            textBlockSetupParm.PrintOnProdJobCard		   = textBlockUsageEntity.TextBlockParm_PrintOnProdJobCard;
            textBlockSetupParm.PrintOnProdRouteCard		   = textBlockUsageEntity.TextBlockParm_PrintOnProdRouteCard;
            textBlockSetupParm.PrintOnProdPickList         = textBlockUsageEntity.TextBlockParm_PrintOnProdPickList;
            textBlockSetupParm.PrintOnProjQuotation		   = textBlockUsageEntity.TextBlockParm_PrintOnProjQuotation;
            textBlockSetupParm.PrintOnProjQuotationConfirm = textBlockUsageEntity.TextBlockParm_PrintOnProjQuotationConfirm;
            textBlockSetupParm.PrintOnProjInvoice		   = textBlockUsageEntity.TextBlockParm_PrintOnProjInvoice;
            textBlockSetupParm.PrintOnPurchReq  		   = textBlockUsageEntity.TextBlockParm_PrintOnPurchReq;
            textBlockSetupParm.PrintOnPurchRFQCase		   = textBlockUsageEntity.TextBlockParm_PrintOnPurchRFQCase;
        }
		else
        {
            textBlockSetupParm.ICCopy                      = textBlockSetupGroupParm.ICCopy;
            textBlockSetupParm.DirectDeliveryCopy		   = textBlockSetupGroupParm.DirectDeliveryCopy;
            textBlockSetupParm.RelatedPOCopy			   = textBlockSetupGroupParm.RelatedPOCopy;
            //textBlockSetupParm.InstanceRelationType        = textBlockSetupGroupParm.InstanceRelationType;	// would be the wrong type (of FWFTextBlockParm-instance from SetupGroup)
            textBlockSetupParm.Position                    = textBlockSetupGroupParm.Position;
            textBlockSetupParm.PrintOnPurchConfirmation    = textBlockSetupGroupParm.PrintOnPurchConfirmation;
            textBlockSetupParm.PrintOnPurchInvoice         = textBlockSetupGroupParm.PrintOnPurchInvoice;
            textBlockSetupParm.PrintOnPurchPackingSlip     = textBlockSetupGroupParm.PrintOnPurchPackingSlip;
            textBlockSetupParm.PrintOnPurchReceiptsList    = textBlockSetupGroupParm.PrintOnPurchReceiptsList;
            textBlockSetupParm.PrintOnSalesConfirmation    = textBlockSetupGroupParm.PrintOnSalesConfirmation;
            textBlockSetupParm.PrintOnSalesInvoice         = textBlockSetupGroupParm.PrintOnSalesInvoice;
            textBlockSetupParm.PrintOnSalesPackingSlip     = textBlockSetupGroupParm.PrintOnSalesPackingSlip;
            textBlockSetupParm.PrintOnSalesPickingList     = textBlockSetupGroupParm.PrintOnSalesPickingList;
            textBlockSetupParm.PrintOnSalesQuotation       = textBlockSetupGroupParm.PrintOnSalesQuotation;
            textBlockSetupParm.ShowWarning                 = textBlockSetupGroupParm.ShowWarning;
            textBlockSetupParm.SortOrder                   = textBlockSetupGroupParm.SortOrder;
            textBlockSetupParm.PrintOnCustFreeInvoice      = textBlockSetupGroupParm.PrintOnCustFreeInvoice;
            textBlockSetupParm.PrintOnPurchAgreement       = textBlockSetupGroupParm.PrintOnPurchAgreement;
            textBlockSetupParm.PrintOnSalesAgreement       = textBlockSetupGroupParm.PrintOnSalesAgreement;
            textBlockSetupParm.PrintOnProdJobCard		   = textBlockSetupGroupParm.PrintOnProdJobCard;
            textBlockSetupParm.PrintOnProdRouteCard		   = textBlockSetupGroupParm.PrintOnProdRouteCard;
            textBlockSetupParm.PrintOnProdPickList         = textBlockSetupGroupParm.PrintOnProdPickList;
            textBlockSetupParm.PrintOnProjQuotation		   = textBlockSetupGroupParm.PrintOnProjQuotation;
            textBlockSetupParm.PrintOnProjQuotationConfirm = textBlockSetupGroupParm.PrintOnProjQuotationConfirm;
            textBlockSetupParm.PrintOnProjInvoice		   = textBlockSetupGroupParm.PrintOnProjInvoice;
            textBlockSetupParm.PrintOnPurchReq  		   = textBlockSetupGroupParm.PrintOnPurchReq;
            textBlockSetupParm.PrintOnPurchRFQCase		   = textBlockSetupGroupParm.PrintOnPurchRFQCase;
        }
		textBlockSetupParm.write();

        if (! textBlockUsage.SetupRefRefId)
        {
            textBlockUsage.selectForUpdate(true);
            textBlockUsage.SetupRefRefId = textBlockSetupParm.RecId;
            textBlockUsage.update();
        }
    }

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    FWFTextBlockUsage textBlockUsage;

    switch (_dataSourceCtx.name())
    {
        case dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage):
            textBlockUsage = _dataSourceCtx.getBuffer();

            if (this.InventInventoryDimensionEntityFieldsMapping::isAnyInventDimFieldSet())
            {
                InventDim inventDim;
                this.InventInventoryDimensionEntityFieldsMapping::updateInventDim(inventDim);
                textBlockUsage.InventDimId = InventDim::findOrCreate(inventDim).inventDimId;
            }

            break;
    }

    super(_entityCtx, _dataSourceCtx);

    switch (_dataSourceCtx.name())
    {
        case dataEntityDataSourceStr(FWFTextBlockUsageEntity, InventDim):
            textBlockUsage = _entityCtx.getRuntimeContextByName(dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage)).getBuffer();
            _dataSourceCtx.setBuffer(textBlockUsage.inventDim());
            break;
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
public void mapDataSourceToEntity(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage))
    {
        FWFTextBlockUsage textBlockUsage = _dataSourceCtx.getBuffer();
        this.InventInventoryDimensionEntityFieldsMapping::initFromInventDim(textBlockUsage.inventDim());
    }

    super(_entityCtx, _dataSourceCtx);
}

    /// <summary>
    ///
    /// </summary>
    /// <param name = "_entityCtx"></param>
    /// <param name = "_dataSourceCtx"></param>
    public void initializeEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
    {
        FWFTextBlockUsageEntity	entityRecord = _entityCtx.getEntityRecord();
        FWFTextBlockTable		textBlockTable;
        InventDim				inventDim;
        InventDimId				inventDimId;
		FWFTextBlockUsage		textBlockUsage;

		if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockUsageEntity, FWFTextBlockUsage))
        {
            select firstonly RecId from textBlockTable
                where textBlockTable.Name		== entityRecord.TextBlockTable_Name
                   && textBlockTable.Module		== entityRecord.TextBlockTable_Module
                   && textBlockTable.CompanyId	== entityRecord.TextBlockTable_CompanyId;

            inventDim.InventSiteId	= entityRecord.InventorySiteId;
            inventDim.configId		= entityRecord.ProductConfigurationId;
            inventDim.InventColorId	= entityRecord.ProductColorId;
            inventDim.InventSizeId	= entityRecord.ProductSizeId;
            inventDim.InventStyleId	= entityRecord.ProductStyleId;
            inventDimId = InventDim::findOrCreate(inventDim).inventDimId;

            select firstonly textBlockUsage
				where textBlockUsage.TextBlockRecId	 == textBlockTable.RecId
                   && textBlockUsage.ProductType	 == entityRecord.ProductType
                   && textBlockUsage.ItemCode		 == entityRecord.ItemCode
                   && textBlockUsage.ItemRelation	 == entityRecord.ItemRelation
                   && textBlockUsage.AccountType	 == entityRecord.AccountType
                   && textBlockUsage.AccountCode	 == entityRecord.AccountCode
                   && textBlockUsage.AccountRelation == entityRecord.AccountRelation
                   && textBlockUsage.InventDimId	 == inventDimId
				   && textBlockUsage.FromDate		 == entityRecord.FromDate;

			if (textBlockUsage)
			{
				_dataSourceCtx.setDatabaseOperation(DataEntityDatabaseOperation::Update);
                _dataSourceCtx.setBuffer(textBlockUsage);
			}
			else
			{
				_dataSourceCtx.setDatabaseOperation(DataEntityDatabaseOperation::Insert);
			}

        }

        super(_entityCtx, _dataSourceCtx);

    }
